// LAYER 1+2: Extract & Validate for reschedule
// Zero-throw: returns Standard Contract error, never throws

const raw = $input.first().json;
const input = (raw.body && typeof raw.body === 'object') ? raw.body : raw;

// UUID regex pattern
const UUID_RE = /^[0-9a-f]{8}-[0-9a-f]{4}-[0-9a-f]{4}-[0-9a-f]{4}-[0-9a-f]{12}$/i;
// ISO 8601 with timezone
function isIsoDate(str) {
  if (!str || !str.includes('T')) return false;
  const tzMatch = str.match(/(Z|[+-]\d{2}:\d{2})$/);
  if (!tzMatch) return false;
  const d = new Date(str);
  if (isNaN(d.getTime())) return false;
  const parts = str.match(/^(\d{4})-(\d{2})-(\d{2})T/);
  if (!parts) return false;
  const [_, year, month, day] = parts;
  if (parseInt(month) !== d.getUTCMonth() + 1) return false;
  if (parseInt(day) !== d.getUTCDate()) return false;
  return true;
}

function ve(code, msg) {
  return [{ json: {
    success: false, error_code: code, error_message: msg, data: null,
    _meta: { source: 'DB_Reschedule_Booking', timestamp: new Date().toISOString(), workflow_id: $workflow.id },
    _exit_early: true
  }}];
}

// === BOOKING_ID VALIDATION ===
const booking_id = String(input.booking_id || '').trim();
if (!booking_id) return ve('MISSING_FIELD', 'booking_id is required');
if (!UUID_RE.test(booking_id)) return ve('INVALID_TYPE', 'booking_id must be a valid UUID');

// === NEW_START_TIME VALIDATION ===
const new_start_time = String(input.new_start_time || '').trim();
if (!new_start_time) return ve('MISSING_FIELD', 'new_start_time is required');
if (!isIsoDate(new_start_time)) return ve('INVALID_TYPE', 'new_start_time must be ISO 8601 with timezone');

const newDate = new Date(new_start_time);
const now = Date.now();
if (newDate.getTime() < now) return ve('PAST_DATE', 'Cannot reschedule to the past');
const ONE_YEAR_MS = 365 * 24 * 60 * 60 * 1000;
if (newDate.getTime() > (now + ONE_YEAR_MS)) return ve('FUTURE_DATE_TOO_EXTREME', 'Rescheduling limited to 1 year in advance');

// === PROVIDER_ID / SERVICE_ID (optional, default to existing) ===
let provider_id = null;
if (input.provider_id !== undefined && input.provider_id !== null) {
  const pidStr = String(input.provider_id).trim();
  const INT_RE = /^\d+$/;
  if (!pidStr || !INT_RE.test(pidStr)) return ve('INVALID_TYPE', 'provider_id must be a positive integer');
  provider_id = parseInt(pidStr);
}

let service_id = null;
if (input.service_id !== undefined && input.service_id !== null) {
  const sidStr = String(input.service_id).trim();
  const INT_RE = /^\d+$/;
  if (!sidStr || !INT_RE.test(sidStr)) return ve('INVALID_TYPE', 'service_id must be a positive integer');
  service_id = parseInt(sidStr);
}

// === CHAT_ID (optional) ===
let chat_id = null;
if (input.chat_id !== undefined && input.chat_id !== null) {
  const cidStr = String(input.chat_id).trim();
  const INT_RE = /^\d+$/;
  if (!cidStr || !INT_RE.test(cidStr)) return ve('INVALID_TYPE', 'chat_id must be a non-negative integer');
  chat_id = parseInt(cidStr);
}

// === RESCHEDULE_REASON (optional) ===
let reschedule_reason = null;
if (input.reschedule_reason !== undefined && input.reschedule_reason !== null) {
  reschedule_reason = String(input.reschedule_reason).trim();
  if (reschedule_reason.length > 500) return ve('INVALID_INPUT', 'reschedule_reason must be <= 500 chars');
}

return [{ json: {
  success: true,
  booking_id,
  new_start_time,
  provider_id,
  service_id,
  chat_id,
  reschedule_reason,
  _validated: true
}}];

// Gate: _exit_early items skip
// Valid items: build check booking exists query
const input = $input.first().json;

if (input._exit_early) {
  return [{ json: { ...input, check_query: "SELECT NULL WHERE FALSE;" } }];
}

const { booking_id } = input;
const safeId = booking_id.replace(/'/g, "''");

// Check if booking exists and get current details
const check_query = `SELECT id, status, provider_id, service_id, start_time FROM bookings WHERE id = '${safeId}'::uuid LIMIT 1;`;

return [{ json: { ...input, check_query } }];

// Handle DB error during check
const e = $input.first().json;
const upstreamData = $('Build Check Query').isExecuted ? $('Build Check Query').first().json : {};
let error_code = 'CHECK_FAILED';
let error_message = e.message || e.error?.message || 'Failed to check booking';

if (error_message.includes('invalid input syntax for type uuid')) {
  error_code = 'INVALID_UUID';
  error_message = 'booking_id is not a valid UUID format';
} else if (error_message.includes('connection') || error_message.includes('ECONNREFUSED')) {
  error_code = 'DB_CONNECTION_ERROR';
  error_message = 'Database connection failed';
} else if (error_message.includes('timeout')) {
  error_code = 'DB_TIMEOUT';
  error_message = 'Database query timeout';
}

return [{ json: {
  ...upstreamData,
  success: false, error_code, error_message, data: null,
  _meta: { source: 'DB_Reschedule_Booking', timestamp: new Date().toISOString(), workflow_id: $workflow.id }
}}];

// DECISION NODE — Check booking exists and can be rescheduled
const pgResult = $input.first().json;
const upstreamData = $('Build Check Query').isExecuted ? $('Build Check Query').first().json : null;

// Pass-through validation errors
if (upstreamData && upstreamData._exit_early) {
  return [{ json: { ...upstreamData, _route: 'error' } }];
}

if (!upstreamData || !upstreamData._validated) {
  return [{ json: {
    success: false, error_code: 'PIPELINE_ERROR',
    error_message: 'Validated data lost in Route By Exists',
    data: null, _route: 'error',
    _meta: { source: 'DB_Reschedule_Booking', timestamp: new Date().toISOString(), workflow_id: $workflow.id }
  }}];
}

// Check if booking was found
const bookingFound = pgResult && pgResult.id !== undefined && pgResult.id !== null;

if (!bookingFound) {
  return [{ json: {
    success: false, error_code: 'NOT_FOUND',
    error_message: 'Booking not found',
    data: null,
    _meta: { source: 'DB_Reschedule_Booking', timestamp: new Date().toISOString(), workflow_id: $workflow.id },
    _route: 'not_found'
  }}];
}

// Check if already cancelled
const status = pgResult.status || '';
if (status === 'CANCELLED') {
  return [{ json: {
    success: false, error_code: 'ALREADY_CANCELLED',
    error_message: 'Cannot reschedule a cancelled booking',
    data: { booking_id: upstreamData.booking_id, status: 'CANCELLED' },
    _meta: { source: 'DB_Reschedule_Booking', timestamp: new Date().toISOString(), workflow_id: $workflow.id },
    _route: 'already_cancelled'
  }}];
}

// Get existing provider_id and service_id if not provided
const existing_provider_id = pgResult.provider_id || upstreamData.provider_id;
const existing_service_id = pgResult.service_id || upstreamData.service_id;

// Booking exists and can be rescheduled — proceed
return [{ json: {
  ...upstreamData,
  existing_status: status,
  existing_provider_id: upstreamData.provider_id || existing_provider_id,
  existing_service_id: upstreamData.service_id || existing_service_id,
  existing_start_time: pgResult.start_time,
  _route: 'reschedule'
}}];

// GATE: Only process items with _route === 'reschedule'
const input = $input.first().json;

if (input._route !== 'reschedule') {
  return [];
}

const { booking_id, new_start_time, reschedule_reason, existing_provider_id, existing_service_id } = input;
const safeId = booking_id.replace(/'/g, "''");
const safeReason = reschedule_reason ? reschedule_reason.replace(/'/g, "''") : null;
const safeNewTime = new_start_time.replace(/'/g, "''");

// UPDATE booking start_time (and optionally provider_id, service_id)
const provider_id = input.provider_id || existing_provider_id;
const service_id = input.service_id || existing_service_id;

const reschedule_query = `UPDATE bookings SET start_time = '${safeNewTime}'::timestamptz, provider_id = ${provider_id}::int, service_id = ${service_id}::int, updated_at = NOW() WHERE id = '${safeId}'::uuid RETURNING id, status, start_time;`;

return [{ json: { ...input, reschedule_query } }];

// GATE: Pass through non-reschedule routes to Format Response
const input = $input.first().json;

if (input._route === 'reschedule') {
  return [];
}

// Pass through error/not_found/already_cancelled responses
return [{ json: input }];

// Format success — booking rescheduled
const result = $input.first().json;
const upstreamData = $('Build Reschedule Query').isExecuted ? $('Build Reschedule Query').first().json : {};
const booking_id = result.id || upstreamData.booking_id;

if (!booking_id) {
  return [{ json: {
    success: false, error_code: 'DB_ERROR',
    error_message: 'Reschedule succeeded but no booking_id returned',
    data: null,
    _meta: { source: 'DB_Reschedule_Booking', timestamp: new Date().toISOString(), workflow_id: $workflow.id }
  }}];
}

return [{ json: {
  success: true, error_code: null, error_message: null,
  data: { 
    booking_id, 
    status: result.status || 'CONFIRMED', 
    rescheduled: true,
    new_start_time: result.start_time || upstreamData.new_start_time
  },
  _meta: { source: 'DB_Reschedule_Booking', timestamp: new Date().toISOString(), workflow_id: $workflow.id }
}}];

// Handle Reschedule error
const e = $input.first().json;
const upstreamData = $('Build Reschedule Query').isExecuted ? $('Build Reschedule Query').first().json : {};
let error_code = 'DB_RESCHEDULE_ERROR';
let error_message = e.message || e.error?.message || 'Failed to reschedule booking';

if (error_message.includes('violates foreign key')) {
  error_code = 'FK_VIOLATION';
  error_message = 'Foreign key constraint violation';
} else if (error_message.includes('connection') || error_message.includes('ECONNREFUSED')) {
  error_code = 'DB_CONNECTION_ERROR';
  error_message = 'Database connection failed during reschedule';
} else if (error_message.includes('timeout')) {
  error_code = 'DB_TIMEOUT';
  error_message = 'Database reschedule timeout';
}

return [{ json: {
  ...upstreamData,
  success: false, error_code, error_message, data: null,
  _meta: { source: 'DB_Reschedule_Booking', timestamp: new Date().toISOString(), workflow_id: $workflow.id }
}}];

// UNIFIED OUTPUT — Standard Contract (§3.2)
const input = $input.first().json;

// Process items that have data OR error_code set
if (input.data !== undefined || input.error_code !== undefined) {
  return [{ json: {
    success: input.success === true,
    error_code: input.error_code || null,
    error_message: input.error_message || null,
    data: input.data || null,
    _meta: input._meta || {
      source: 'DB_Reschedule_Booking',
      timestamp: new Date().toISOString(),
      workflow_id: $workflow.id
    }
  }}];
}

// Otherwise, pass-through item — skip it
return [];
